export function parseArgs(argv) {
  const result = { _: [] }

  for (let i = 0; i < argv.length; i++) {
    const arg = argv[i]

    // Positional argument (doesn't start with --)
    if (!arg.startsWith('--')) {
      result._.push(arg)
      continue
    }

    // --key=value syntax
    if (arg.includes('=')) {
      const [key, value] = arg.split('=', 2)
      result[key.slice(2)] = value
      continue
    }

    // --key value syntax (next arg is the value)
    if (i + 1 < argv.length && !argv[i + 1].startsWith('--')) {
      result[arg.slice(2)] = argv[i + 1]
      i++
      continue
    }

    // Boolean flag
    result[arg.slice(2)] = true
  }

  return result
}
